mapper.select:
SELECT P.NOTICE_ID AS noticeId, P.TITLE AS title, P.IS_URGENT AS isUrgent, P.IS_PINNED AS isPinned, P.VIEW_CNT AS viewCnt, P.USER_ID AS userId, U.NAME AS userName, P.CREATED_AT AS createdAt FROM r_notice_post_t P LEFT JOIN USER U ON P.USER_ID = U.USER_ID WHERE P.DEL_YN = 'N'
AND (P.TITLE LIKE CONCAT('%', #{search}, '%') OR P.CONTENT LIKE CONCAT('%', #{search}, '%'))
ORDER BY P.IS_PINNED DESC, P.NOTICE_ID DESC LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE r_notice_post_t
SET DEL_YN = 'Y'
WHERE NOTICE_ID = #{noticeId}

UPDATE r_notice_post_t
SET VIEW_CNT = VIEW_CNT + 1
WHERE NOTICE_ID = #{noticeId}
